// 批量更新 OKR
const rawBody = $input.first().json.rawBody;
const updates = rawBody.updates;
let currentData = { meta: { year: 2026, currentQuarter: 'Q1' }, businesses: [] };
for (const update of updates) {
  const biz = currentData.businesses.find(b => b.id === update.business);
  if (biz) {
    if (update.objectiveIndex !== undefined && update.krIndex !== undefined) {
      const obj = biz.objectives[update.objectiveIndex];
      if (obj && obj.keyResults[update.krIndex]) obj.keyResults[update.krIndex].progress = update.progress;
    }
    if (update.overallProgress !== undefined) biz.overallProgress = update.overallProgress;
  }
}
return [{ json: { result: 'batch_updated', count: updates.length, data: currentData } }]

// 单条 OKR 更新
const raw = $input.first().json.rawBody;
let currentData = { meta: { year: 2026, currentQuarter: 'Q1' }, businesses: [] };
const biz = currentData.businesses.find(b => b.id === raw.business);
if (biz) {
  if (raw.objectiveIndex !== undefined && raw.krIndex !== undefined) {
    const obj = biz.objectives[raw.objectiveIndex];
    if (obj && obj.keyResults[raw.krIndex]) obj.keyResults[raw.krIndex].progress = raw.progress;
  }
  if (raw.overallProgress !== undefined) biz.overallProgress = raw.overallProgress;
}
return [{ json: { result: 'single_updated', business: raw.business, data: currentData } }]

// ====== WorkBuddy 任务进度处理 ======
// 接收来自 workbuddy-bridge.js 的任务状态更新
// 将其写入 workbuddy_tasks 表或追加到 state.json 的 workbuddyTasks 数组

const taskData = $input.first().json.taskData;
if (!taskData) return [{ json: { error: 'no task data found' } }];

// 构造标准化的任务对象
const normalizedTask = {
  id: taskData.id,
  title: taskData.title,
  progress: taskData.progress || 0,
  step: taskData.step || '',
  status: taskData.status || 'pending',
  session: taskData.session || 'unknown',
  startedAt: taskData.startedAt || null,
  updatedAt: new Date().toISOString(),
};

// 返回结果 — 后续节点写入 Supabase 或本地文件
return [{ 
  json: { 
    action: 'workbuddy_task_synced',
    task: normalizedTask,
    timestamp: new Date().toISOString()
  }
}]

// 渲染罗盘 HTML
const inputItem = $input.first();
let okrData = null;
try {
  okrData = typeof inputItem.json.data === 'string' ? JSON.parse(inputItem.json.data) : inputItem.json.data;
} catch(e) { okrData = null; }
if (!okrData) okrData = { meta: { year: 2026, currentQuarter: 'Q1' }, businesses: [], workbuddyTasks: [] };
return [{ json: { htmlGenerated: true, dataTimestamp: okrData?.meta?.lastUpdated || 'N/A', okrData } }]

// 组装最终 HTML：注入动态数据到模板
const templateItem = $input.item.find(i => i.binary?.data);
const renderItem = $input.item.find(i => i.json?.htmlGenerated);
let html = '';
if (templateItem) html = templateItem.binary.data.data.toString('utf8');

const okrData = renderItem?.json?.okrData || {};
const scriptTag = `<script>window.__OKR_INJECTED__=${JSON.stringify(okrData)};</script>`;
const injectionPoint = '</body>';
if (html.includes(injectionPoint)) {
  html = html.replace(injectionPoint, scriptTag + '\n' + injectionPoint);
} else { html += scriptTag; }
return [{ json: { outputHtml: html, generatedAt: new Date().toISOString(), size: html.length } }]
